{
  "executive_summary": "A food delivery platform connecting restaurants, customers, and delivery drivers was requested, but critical non-functional requirements, scale targets, integration boundaries, and business constraints are missing. Without these, recommending a specific architectural pattern (monolith vs microservices, sync vs async, SQL vs NoSQL, etc.) would be speculation. This analysis identifies what is known, what is missing, and what questions must be answered before architecture decisions can be made responsibly.",

  "architecture": {
    "components": [
      { "name": "Order Management", "responsibility": "Lifecycle of orders from placement through completion", "boundaries": "Core transactional flow — must protect order state invariants" },
      { "name": "Restaurant Management", "responsibility": "Restaurant profiles, menus, availability, hours", "boundaries": "Restaurant-facing; menu and catalog data" },
      { "name": "Customer Experience", "responsibility": "Search, browsing, cart, order placement, order tracking", "boundaries": "Customer-facing interactions" },
      { "name": "Delivery & Dispatch", "responsibility": "Driver matching, route optimization, real-time tracking", "boundaries": "Driver-facing; location-heavy; real-time" },
      { "name": "Payments & Billing", "responsibility": "Payment processing, refunds, restaurant payouts, driver payouts", "boundaries": "Financial transactions — high integrity requirements" },
      { "name": "Notifications", "responsibility": "Push notifications, SMS, email for all actors", "boundaries": "Cross-cutting; event-driven" },
      { "name": "Identity & Auth", "responsibility": "Authentication and authorization for three actor types", "boundaries": "Generic subdomain; multi-tenant identity" }
    ],
    "interfaces": [
      { "from": "Customer Experience", "to": "Order Management", "contract": "Place order, cancel order, track order status", "coupling_type": "synchronous (order placement) + async (status updates)" },
      { "from": "Order Management", "to": "Restaurant Management", "contract": "Validate menu items, confirm restaurant availability, notify restaurant of new order", "coupling_type": "synchronous for validation, async for notification" },
      { "from": "Order Management", "to": "Delivery & Dispatch", "contract": "Request driver assignment when order is confirmed by restaurant", "coupling_type": "async — event-driven" },
      { "from": "Order Management", "to": "Payments & Billing", "contract": "Authorize payment on order placement, capture on delivery, handle refunds", "coupling_type": "synchronous for authorization, async for settlement" },
      { "from": "Delivery & Dispatch", "to": "Notifications", "contract": "Emit location updates and status changes for customer tracking", "coupling_type": "async — event/stream" },
      { "from": "Order Management", "to": "Notifications", "contract": "Emit order state transitions (confirmed, preparing, picked up, delivered)", "coupling_type": "async — event-driven" }
    ],
    "data_flow": "Customer places order → Order Management validates menu via Restaurant Management → Payment authorized via Payments → Order confirmed → Restaurant notified → Restaurant marks ready → Delivery & Dispatch assigns driver → Driver picks up → Real-time tracking via Delivery & Dispatch → Delivery confirmed → Payment captured → Payouts scheduled",
    "patterns_used": []
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Ordering",
        "classification": "core",
        "aggregates": ["Order (root: OrderId — contains OrderItems, tracks state machine: placed→confirmed→preparing→ready→picked_up→delivered→completed)", "Cart (ephemeral, pre-order)"]
      },
      {
        "name": "Delivery",
        "classification": "core",
        "aggregates": ["DeliveryAssignment (root: AssignmentId — links Order to Driver, tracks pickup/dropoff)", "DriverAvailability (root: DriverId — location, status, capacity)"]
      },
      {
        "name": "Restaurant Catalog",
        "classification": "supporting",
        "aggregates": ["Restaurant (root: RestaurantId — profile, hours, service area)", "Menu (root: MenuId — categories, items, pricing, availability)"]
      },
      {
        "name": "Payments",
        "classification": "generic",
        "aggregates": ["PaymentTransaction (root: TransactionId — authorization, capture, refund)", "Payout (root: PayoutId — scheduled disbursements to restaurants and drivers)"]
      },
      {
        "name": "Identity",
        "classification": "generic",
        "aggregates": ["Account (root: AccountId — credentials, roles, profile for customer/restaurant/driver)"]
      },
      {
        "name": "Notifications",
        "classification": "generic",
        "aggregates": ["NotificationPreference", "NotificationLog"]
      }
    ],
    "context_map": [
      { "upstream": "Ordering", "downstream": "Delivery", "relationship": "Customer-Supplier — Ordering dictates when delivery is needed; Delivery fulfills" },
      { "upstream": "Restaurant Catalog", "downstream": "Ordering", "relationship": "Conformist — Ordering conforms to menu/pricing defined by Restaurant Catalog" },
      { "upstream": "Ordering", "downstream": "Payments", "relationship": "Customer-Supplier — Ordering triggers payment lifecycle events" },
      { "upstream": "Ordering", "downstream": "Notifications", "relationship": "Open Host Service — Ordering publishes domain events; Notifications subscribes" },
      { "upstream": "Delivery", "downstream": "Notifications", "relationship": "Open Host Service — Delivery publishes location/status events" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Cannot recommend monolith vs microservices without scale/team constraints",
      "gains": "Avoiding premature distributed complexity if team is small; avoiding monolith bottleneck if team is large",
      "sacrifices": "Decision deferred — blocks detailed infrastructure design",
      "alternatives_considered": ["Modular monolith (small team, <100K orders/day)", "Microservices (multiple teams, >1M orders/day)", "Hybrid: monolith with extracted Delivery service (medium scale)"]
    },
    {
      "decision": "Cannot recommend real-time tracking architecture without latency/scale NFRs",
      "gains": "Right-sized solution for actual driver fleet size",
      "sacrifices": "Decision deferred",
      "alternatives_considered": ["WebSocket with in-memory pub/sub (small scale)", "Kafka + WebSocket gateway (large scale)", "Server-Sent Events with Redis pub/sub (medium scale)"]
    },
    {
      "decision": "Cannot recommend dispatch algorithm complexity without geographic/business constraints",
      "gains": "Appropriate investment in optimization",
      "sacrifices": "Decision deferred",
      "alternatives_considered": ["Simple nearest-driver assignment", "Batched optimization with cost functions", "ML-based predictive dispatch"]
    }
  ],

  "flexibility_points": [
    { "area": "Dispatch algorithm", "evolution_path": "Start with simple nearest-available, evolve to batched optimization as driver fleet grows" },
    { "area": "Payment provider", "evolution_path": "Abstract behind a payment gateway interface — swap Stripe/Adyen/etc. without order flow changes" },
    { "area": "Notification channels", "evolution_path": "Event-driven design allows adding new channels (push, SMS, email, in-app) without modifying publishers" },
    { "area": "Menu/catalog complexity", "evolution_path": "Start with flat menu items, evolve to modifiers/customizations/combos as restaurant needs grow" }
  ],

  "rigidity_points": [
    { "area": "Order state machine", "reason": "Core invariant — state transitions must be strictly enforced and auditable. Changing this affects every downstream consumer." },
    { "area": "Payment transaction integrity", "reason": "Financial correctness is non-negotiable — authorization/capture/refund flow must be ACID and idempotent" },
    { "area": "Order-to-Delivery handoff contract", "reason": "This is the critical integration seam between the two core contexts — must be stable and versioned" }
  ],

  "risks": [
    { "risk": "Choosing microservices prematurely could introduce distributed systems complexity that a small team cannot sustain", "severity": "high", "mitigation": "Clarify team size and scale targets before committing to deployment topology" },
    { "risk": "Real-time driver tracking at scale requires specialized infrastructure (geo-indexing, high-frequency updates) that is expensive to retrofit", "severity": "high", "mitigation": "Clarify expected driver fleet size and update frequency requirements early" },
    { "risk": "Three-sided marketplace (customer, restaurant, driver) creates complex failure modes — e.g., restaurant accepts but no driver available, driver cancels mid-delivery", "severity": "medium", "mitigation": "Design explicit compensation/fallback flows for each failure scenario in the order state machine" },
    { "risk": "Geographic constraints (single city vs multi-city vs multi-country) fundamentally affect data partitioning, regulatory compliance, and currency handling", "severity": "high", "mitigation": "Clarify geographic scope before designing data architecture" }
  ],

  "implementation_guidance": {
    "recommended_approach": "",
    "files_to_create_or_modify": [],
    "patterns_to_follow": "",
    "pitfalls_to_avoid": [
      "Do not choose microservices vs monolith without knowing team size and expected order volume",
      "Do not design the real-time tracking layer without knowing driver fleet size and acceptable latency",
      "Do not assume single-currency or single-region — geographic scope changes everything",
      "Do not over-invest in dispatch optimization before product-market fit"
    ]
  },

  "escalations": [
    {
      "type": "missing_constraints",
      "description": "Critical non-functional requirements are missing. Cannot make responsible architecture decisions without: (1) Expected scale — orders/day, concurrent users, driver fleet size. (2) Team size and structure — determines monolith vs microservices vs modular monolith. (3) Geographic scope — single city, multi-city, multi-country affects data partitioning, compliance, currency. (4) Latency requirements — especially for real-time tracking and dispatch. (5) Tech stack preferences or existing infrastructure. (6) Budget and infrastructure constraints (cloud provider, managed services vs self-hosted). (7) Reliability targets (SLA for order placement, payment processing). (8) Integration requirements (existing POS systems, payment providers, mapping APIs).",
      "routed_to": "user",
      "options": [
        "Provide scale targets (orders/day, users, drivers) to unlock deployment topology decision",
        "Provide team size to determine monolith vs microservices recommendation",
        "Provide geographic scope to determine data architecture",
        "Provide all of the above for a complete architecture recommendation"
      ],
      "recommendation": "Provide at minimum: expected scale (orders/day), team size, geographic scope, and target tech stack. With these four constraints, a concrete architecture can be recommended."
    }
  ],

  "confidence": {
    "level": 45,
    "high_confidence_areas": [
      "Bounded context identification — Ordering, Delivery, Restaurant Catalog, Payments, Identity, and Notifications are natural seams regardless of implementation",
      "Core vs supporting vs generic classification — Ordering and Delivery are clearly core domain",
      "Order state machine as a rigidity point — this is invariant across all food delivery platforms",
      "Context map relationships — the upstream/downstream dynamics are stable"
    ],
    "low_confidence_areas": [
      "Deployment topology — cannot recommend without team size and scale",
      "Real-time tracking architecture — depends entirely on fleet size and latency requirements",
      "Data store choices — depends on scale, consistency requirements, and team expertise",
      "Dispatch algorithm complexity — depends on geographic scope and business maturity",
      "Infrastructure and cloud architecture — no constraints provided"
    ],
    "assumptions": [
      "This is a new platform (greenfield), not a re-architecture of an existing system",
      "All three actor types (customer, restaurant, driver) will have dedicated client applications",
      "The platform will handle payment processing rather than delegating to restaurants",
      "Real-time order tracking is an expected feature"
    ]
  }
}

